import './FriendList.css'

function FriendList ({options}) {
  return (
    <ul className="friend-list">
      {options.map(option =>
        <li className="item">
          <span className="status">{option.isOnline}</span>
          <img className="avatar" src={option.avatar} alt={option.name} width="48" />
          <p className="name">{option.name}</p>
      </li>

      )}
    </ul>

  )


}
export default FriendList
